import { useState, useEffect } from "react";
import { createPortal } from "react-dom";
import { Link, useNavigate } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { formatDistanceToNow } from "date-fns";
import { zhCN, enUS, pt } from "date-fns/locale";
import { Heart, MessageCircle, Share2, MoreHorizontal, Calendar, X, ChevronLeft, ChevronRight, MapPin, FileImage, ChevronDown, ChevronUp, Pencil, Clock, Sparkles, BookOpen } from "lucide-react";
import WatermarkedVideoPlayer from "@/components/community/WatermarkedVideoPlayer";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  type CarouselApi,
} from "@/components/ui/carousel";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardFooter, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { CommunityPost, useLikePost, useSharePost, useDeletePost } from "@/hooks/useCommunityPosts";
import { useAuth } from "@/contexts/AuthContext";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { toast } from "sonner";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import TranslateButton from "@/components/TranslateButton";
import { useSmartShare, ShareDrawer } from "@/components/ShareDrawer";
import EditPostDialog from "@/components/community/EditPostDialog";
import EditRecipeDialog from "@/components/community/EditRecipeDialog";
import SavedRecipeDetailDialog from "@/components/ai-recipe/SavedRecipeDetailDialog";
import { useLoginRequired } from "@/hooks/useLoginRequired";

interface PostCardProps {
  post: CommunityPost;
  showActions?: boolean;
  isDetailPage?: boolean;
}

const PostCard = ({ post, showActions = true, isDetailPage = false }: PostCardProps) => {
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const navigate = useNavigate();
  const { requireLogin } = useLoginRequired();
  const { getLocalizedField } = useLocalizedContent();
  const likePost = useLikePost();
  const sharePost = useSharePost();
  const deletePost = useDeletePost();
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
  const [showEditDialog, setShowEditDialog] = useState(false);
  const [imageError, setImageError] = useState<Record<string, boolean>>({});
  const [previewOpen, setPreviewOpen] = useState(false);
  const [previewIndex, setPreviewIndex] = useState(0);
  const [carouselApi, setCarouselApi] = useState<CarouselApi>();
  const [previewCarouselApi, setPreviewCarouselApi] = useState<CarouselApi>();
  const [currentSlide, setCurrentSlide] = useState(0);
  const [translatedContent, setTranslatedContent] = useState<string | null>(null);
  const [touchStartX, setTouchStartX] = useState<number | null>(null);
  const [isSwiping, setIsSwiping] = useState(false);
  const [swipeOffset, setSwipeOffset] = useState(0);
  const [isAnimating, setIsAnimating] = useState(false);
  const [imageDimensions, setImageDimensions] = useState<Record<string, { width: number; height: number }>>({});
  const [longImageScrollStart, setLongImageScrollStart] = useState<{ y: number; scrollTop: number } | null>(null);
  const [showAllRestaurants, setShowAllRestaurants] = useState(false);
  const [showAiRecipeDialog, setShowAiRecipeDialog] = useState(false);
  const { share: smartShareFn, DrawerComponent: SmartShareDrawer } = useSmartShare();

  // Lock body scroll when preview is open
  useEffect(() => {
    if (previewOpen) {
      const scrollY = window.scrollY;
      document.body.style.position = 'fixed';
      document.body.style.top = `-${scrollY}px`;
      document.body.style.left = '0';
      document.body.style.right = '0';
      document.body.style.overflow = 'hidden';
      
      return () => {
        document.body.style.position = '';
        document.body.style.top = '';
        document.body.style.left = '';
        document.body.style.right = '';
        document.body.style.overflow = '';
        window.scrollTo(0, scrollY);
      };
    }
  }, [previewOpen]);

  // Listen to carousel slide changes
  useEffect(() => {
    if (!carouselApi) return;
    
    setCurrentSlide(carouselApi.selectedScrollSnap());
    
    carouselApi.on("select", () => {
      setCurrentSlide(carouselApi.selectedScrollSnap());
    });
  }, [carouselApi]);

  const getDateLocale = () => {
    switch (i18n.language) {
      case "zh":
        return zhCN;
      case "pt":
        return pt;
      default:
        return enUS;
    }
  };

  const handleLike = () => {
    if (!requireLogin()) return;
    likePost.mutate({ postId: post.id, liked: post.user_liked || false });
  };

  const handleShare = async () => {
    const shareUrl = `${window.location.origin}/community/post/${post.id}`;
    
    smartShareFn({
      title: t("community.shareTitle", "分享帖子"),
      text: post.content.replace(/<[^>]*>/g, '').substring(0, 100),
      url: shareUrl,
    }, () => {
      if (user) {
        sharePost.mutate(post.id);
      }
      toast.success(t("community.shareSuccess", "分享成功"));
    });
  };

  const handleDelete = () => {
    deletePost.mutate(post.id);
    setShowDeleteDialog(false);
  };

  const handleImageClick = (index: number) => {
    if (isDetailPage) {
      // On detail page, open preview
      setPreviewIndex(index);
      setPreviewOpen(true);
    } else {
      // On feed, navigate to post detail
      navigate(`/community/post/${post.id}`);
    }
  };

  const handlePrevImage = () => {
    if (isAnimating) return;
    setIsAnimating(true);
    setSwipeOffset(window.innerWidth);
    setTimeout(() => {
      setPreviewIndex((prev) => 
        prev === 0 ? (post.image_urls?.length || 1) - 1 : prev - 1
      );
      setSwipeOffset(0);
      setIsAnimating(false);
    }, 250);
  };

  const handleNextImage = () => {
    if (isAnimating) return;
    setIsAnimating(true);
    setSwipeOffset(-window.innerWidth);
    setTimeout(() => {
      setPreviewIndex((prev) => 
        prev === (post.image_urls?.length || 1) - 1 ? 0 : prev + 1
      );
      setSwipeOffset(0);
      setIsAnimating(false);
    }, 250);
  };

  const handleImageLoad = (e: React.SyntheticEvent<HTMLImageElement>, url: string) => {
    const img = e.currentTarget;
    setImageDimensions(prev => ({
      ...prev,
      [url]: { width: img.naturalWidth, height: img.naturalHeight }
    }));
  };

  const isLongImage = (url: string) => {
    const dims = imageDimensions[url];
    return dims ? dims.height / dims.width > 1.5 : false;
  };

  const isAuthor = user?.id === post.author_id;
  const activityTitle = post.activity
    ? getLocalizedField(post.activity, "title")
    : null;
  
  // Get all restaurants (from new junction table + legacy single restaurant)
  const allRestaurants = [
    ...(post.restaurants || []),
    ...(post.restaurant && !post.restaurants?.find(r => r.id === post.restaurant?.id) ? [post.restaurant] : []),
  ];
  
  // Max visible restaurants before collapsing
  const maxVisibleRestaurants = isDetailPage ? 3 : 2;
  const visibleRestaurants = showAllRestaurants 
    ? allRestaurants 
    : allRestaurants.slice(0, maxVisibleRestaurants);
  const hasMoreRestaurants = allRestaurants.length > maxVisibleRestaurants;

  // Get localized content - prioritize pre-stored translations
  const localizedContent = getLocalizedField(post, "content");
  
  // Check if we have a pre-stored translation for current language
  const hasLocalizedTranslation = 
    (i18n.language === "zh" && post.content_zh) ||
    (i18n.language === "en" && post.content_en) ||
    (i18n.language === "pt" && post.content_pt);
  
  // Use localized content, or translated content, or original
  // Convert newlines to <br> for proper display
  const rawContent = translatedContent || localizedContent || post.content;
  const displayContent = rawContent?.replace(/\[\[NOTE\]\]/g, '').replace(/\[\[INTRO\]\]/g, '').replace(/\n/g, '<br>') || '';

  return (
    <>
      <Card className="overflow-hidden">
        <CardHeader className="pb-3">
          <div className="flex items-start justify-between">
            <div className="flex items-center gap-3">
              <Avatar
                className="h-10 w-10 cursor-pointer hover:ring-2 hover:ring-primary/50 transition-all"
                onClick={() => post.author?.id && navigate(`/user/${post.author.id}`)}
              >
                <AvatarImage src={post.author?.avatar_url || undefined} />
                <AvatarFallback>
                  {post.author?.display_name?.charAt(0) || "?"}
                </AvatarFallback>
              </Avatar>
              <div>
                <p
                  className="font-medium text-sm cursor-pointer hover:underline"
                  onClick={() => post.author?.id && navigate(`/user/${post.author.id}`)}
                >
                  {post.author?.display_name}
                </p>
                <p className="text-xs text-muted-foreground">
                  {formatDistanceToNow(new Date(post.created_at), {
                    addSuffix: true,
                    locale: getDateLocale(),
                  })}
                </p>
                {/* Pending status badge for author */}
                {isAuthor && post.status === "pending" && (
                  <Badge variant="outline" className="text-amber-600 border-amber-500 bg-amber-50 dark:bg-amber-950/30 text-xs mt-0.5">
                    <Clock className="w-3 h-3 mr-1" />
                    {t("community.pendingReview", "审核中")}
                  </Badge>
                )}
              </div>
            </div>

            {showActions && isAuthor && (
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="ghost" size="icon" className="h-8 w-8">
                    <MoreHorizontal className="h-4 w-4" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end">
                  <DropdownMenuItem
                    onClick={() => setShowEditDialog(true)}
                  >
                    <Pencil className="h-4 w-4 mr-2" />
                    {t("common.edit", "编辑")}
                  </DropdownMenuItem>
                  <DropdownMenuItem
                    onClick={() => setShowDeleteDialog(true)}
                    className="text-destructive"
                  >
                    {t("common.delete", "删除")}
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            )}
          </div>
        </CardHeader>

        <CardContent className="pt-0 pb-3">
          {/* Activity & Restaurant Badges */}
          {/* Activity, AI Recipe & Restaurant Badges */}
          {(post.activity || allRestaurants.length > 0 || (post as any).ai_recipe_source) && (
            <div className="flex flex-wrap gap-2 mb-3 items-center">
              {(post as any).ai_recipe_source && (
                (post as any).ai_recipe_source?.recipe_name ? (
                  <button onClick={() => setShowAiRecipeDialog(true)}>
                    <Badge variant="secondary" className="gap-1 bg-primary/10 text-primary hover:bg-primary/20 cursor-pointer transition-colors">
                      <BookOpen className="h-3 w-3" />
                      {t("aiRecipe.viewRecipe", "查看食谱")}
                    </Badge>
                  </button>
                ) : (
                  <Badge variant="secondary" className="gap-1 bg-primary/10 text-primary">
                    <Sparkles className="h-3 w-3" />
                    {t("aiRecipe.badge", "AI 食谱")}
                  </Badge>
                )
              )}
              {post.activity && (
                <Link to={`/activity/${post.activity.id}`}>
                  <Badge variant="secondary" className="gap-1">
                    <Calendar className="h-3 w-3" />
                    {activityTitle}
                  </Badge>
                </Link>
              )}
              {visibleRestaurants.map((restaurant) => (
                <Link key={restaurant.id} to={`/restaurant/${restaurant.id}`}>
                  <Badge variant="secondary" className="gap-1">
                    <MapPin className="h-3 w-3" />
                    {getLocalizedField(restaurant, "name")}
                  </Badge>
                </Link>
              ))}
              {hasMoreRestaurants && !showAllRestaurants && (
                <button
                  onClick={() => setShowAllRestaurants(true)}
                  className="text-xs text-muted-foreground hover:text-foreground flex items-center gap-0.5"
                >
                  +{allRestaurants.length - maxVisibleRestaurants} {t("community.more", "更多")}
                  <ChevronDown className="h-3 w-3" />
                </button>
              )}
              {showAllRestaurants && hasMoreRestaurants && (
                <button
                  onClick={() => setShowAllRestaurants(false)}
                  className="text-xs text-muted-foreground hover:text-foreground flex items-center gap-0.5"
                >
                  {t("community.collapse", "收起")}
                  <ChevronUp className="h-3 w-3" />
                </button>
              )}
            </div>
          )}

          {/* Content */}
          <Link to={`/community/post/${post.id}`}>
            <div
              className={`prose prose-sm max-w-none dark:prose-invert ${!isDetailPage ? 'line-clamp-6' : ''}`}
              dangerouslySetInnerHTML={{ __html: displayContent }}
            />
          </Link>

          {/* Translate Button - only show if no pre-stored translation */}
          {!hasLocalizedTranslation && (
            <TranslateButton 
              text={post.content} 
              onTranslation={setTranslatedContent}
              className="mt-1"
            />
          )}

          {/* Images - Carousel only for multiple images */}
          {/* In detail page with video, hide cover images (they only serve as thumbnails in list view) */}
          {(() => {
            // If detail page and post has a video, don't show images (they're just covers)
            if (isDetailPage && post.video_url && !post.video_url.startsWith("blob:")) return null;
            
            const displayImageUrls = post.image_urls;
            
            if (!displayImageUrls || displayImageUrls.length === 0) return null;
            
            return (
              <div className="relative mt-3">
                {displayImageUrls.length === 1 ? (
                  // Single image - always limit max height
                  (() => {
                    const url = displayImageUrls[0];
                    const isLong = isLongImage(url);
                    return (
                      <div 
                        className="relative overflow-hidden rounded-lg cursor-pointer max-h-[300px] sm:max-h-[400px]"
                        onClick={() => handleImageClick(0)}
                      >
                        {!imageError[url] ? (
                          <>
                            <img
                              src={url}
                              alt=""
                              className="w-full max-h-[300px] sm:max-h-[400px] object-cover object-top"
                              onLoad={(e) => handleImageLoad(e, url)}
                              onError={() =>
                                setImageError((prev) => ({ ...prev, [url]: true }))
                              }
                            />
                            {/* Long image indicator */}
                            {isLong && (
                              <div className="absolute bottom-2 right-2 bg-black/60 text-white text-xs px-2 py-0.5 rounded-full flex items-center gap-1">
                                <FileImage className="h-3 w-3" />
                                <span>{t("community.longImage", "长图")}</span>
                              </div>
                            )}
                          </>
                        ) : (
                          <div className="w-full h-full min-h-[200px] bg-muted flex items-center justify-center">
                            <span className="text-xs text-muted-foreground">
                              {t("common.imageLoadError", "图片加载失败")}
                            </span>
                          </div>
                        )}
                      </div>
                    );
                  })()
                ) : (
                  // Multiple images - use carousel with smart display
                  <>
                    <Carousel 
                      setApi={setCarouselApi} 
                      className="w-full"
                      opts={{ loop: true }}
                    >
                      <CarouselContent className="-ml-0">
                        {displayImageUrls.map((url, index) => {
                          const isLong = isLongImage(url);
                          return (
                            <CarouselItem key={index} className="pl-0">
                              <div 
                                className="relative overflow-hidden rounded-lg cursor-pointer aspect-[4/3] bg-muted"
                                onClick={() => handleImageClick(index)}
                              >
                                {!imageError[url] ? (
                                  <>
                                    <img
                                      src={url}
                                      alt=""
                                      className="w-full h-full object-contain"
                                      onLoad={(e) => handleImageLoad(e, url)}
                                      onError={() =>
                                        setImageError((prev) => ({ ...prev, [url]: true }))
                                      }
                                    />
                                    {/* Long image indicator */}
                                    {isLong && (
                                      <div className="absolute bottom-2 right-2 bg-black/60 text-white text-xs px-2 py-0.5 rounded-full flex items-center gap-1">
                                        <FileImage className="h-3 w-3" />
                                        <span>{t("community.longImage", "长图")}</span>
                                      </div>
                                    )}
                                  </>
                                ) : (
                                  <div className="w-full h-full min-h-[200px] bg-muted flex items-center justify-center">
                                    <span className="text-xs text-muted-foreground">
                                      {t("common.imageLoadError", "图片加载失败")}
                                    </span>
                                  </div>
                                )}
                              </div>
                            </CarouselItem>
                          );
                        })}
                      </CarouselContent>
                    </Carousel>
                    
                    {/* Top-right slide counter */}
                    <div className="absolute top-3 right-3 bg-black/60 text-white text-xs px-2 py-1 rounded-full z-10">
                      {currentSlide + 1}/{displayImageUrls.length}
                    </div>
                    
                    {/* Bottom navigation dots */}
                    <div className="flex justify-center gap-1.5 mt-2">
                      {displayImageUrls.map((_, index) => (
                        <button
                          key={index}
                          className={`w-1.5 h-1.5 rounded-full transition-colors ${
                            index === currentSlide 
                              ? "bg-primary" 
                              : "bg-muted-foreground/30"
                          }`}
                          onClick={(e) => {
                            e.stopPropagation();
                            carouselApi?.scrollTo(index);
                          }}
                        />
                      ))}
                    </div>
                  </>
                )}
              </div>
            );
          })()}

          {/* Video with watermark */}
          {post.video_url && !post.video_url.startsWith("blob:") && (
            <div className="mt-3 rounded-lg overflow-hidden bg-gray-900">
              <WatermarkedVideoPlayer
                videoUrl={post.video_url}
                poster={post.image_urls?.length ? post.image_urls[0] : undefined}
              />
            </div>
          )}
        </CardContent>

        <CardFooter className="pt-0 border-t">
          <div className="flex items-center gap-4 pt-3 w-full">
            <Button
              variant="ghost"
              size="sm"
              className={`gap-2 ${post.user_liked ? "text-red-500" : ""}`}
              onClick={handleLike}
              disabled={!user}
            >
              <Heart
                className={`h-4 w-4 ${post.user_liked ? "fill-current" : ""}`}
              />
              <span>{post.likes_count}</span>
            </Button>

            <Button
              variant="ghost"
              size="sm"
              className="gap-2"
              onClick={() => {
                if (!requireLogin()) return;
                navigate(`/community/post/${post.id}`);
              }}
            >
              <MessageCircle className="h-4 w-4" />
              <span>{post.comments_count}</span>
            </Button>

            <Button variant="ghost" size="sm" className="gap-2" onClick={handleShare}>
              <Share2 className="h-4 w-4" />
              <span>{post.shares_count}</span>
            </Button>
          </div>
        </CardFooter>
      </Card>

      <AlertDialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t("common.confirmDelete", "确认删除")}</AlertDialogTitle>
            <AlertDialogDescription>
              {t("community.deleteWarning", "删除后无法恢复，确定要删除这篇帖子吗？")}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t("common.cancel", "取消")}</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete}>
              {t("common.delete", "删除")}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Edit Dialog - type-aware */}
      {(post as any).post_type === 'recipe' ? (
        <EditRecipeDialog
          post={post}
          open={showEditDialog}
          onOpenChange={setShowEditDialog}
        />
      ) : (
        <EditPostDialog
          post={post}
          open={showEditDialog}
          onOpenChange={setShowEditDialog}
        />
      )}

      {/* Image Preview - Using Carousel for smooth swipe like feed */}
      {previewOpen && createPortal(
        <div 
          className="fixed inset-0 z-[100] bg-black overflow-hidden"
          onClick={(e) => {
            // Only close if clicking on backdrop, not carousel
            if (e.target === e.currentTarget) {
              setPreviewOpen(false);
            }
          }}
          onWheel={(e) => e.stopPropagation()}
          onTouchMove={(e) => e.stopPropagation()}
        >
          {/* Image Counter */}
          {post.image_urls && post.image_urls.length > 1 && (
            <div className="absolute top-4 left-1/2 -translate-x-1/2 z-10 text-white text-sm bg-black/50 px-4 py-1.5 rounded-full">
              {previewIndex + 1} / {post.image_urls.length}
            </div>
          )}

          {/* Close Button */}
          <Button
            variant="ghost"
            size="icon"
            className="absolute top-4 right-4 z-10 text-white hover:bg-white/20"
            onClick={() => setPreviewOpen(false)}
          >
            <X className="h-6 w-6" />
          </Button>

          {/* Full screen Carousel - centered with calc() constraints */}
          <div className="absolute inset-0 flex items-center justify-center">
            <Carousel
              className="w-full"
              opts={{ loop: true, startIndex: previewIndex }}
              setApi={(api) => {
                setPreviewCarouselApi(api);
                if (api) {
                  api.on("select", () => {
                    setPreviewIndex(api.selectedScrollSnap());
                  });
                }
              }}
            >
              <CarouselContent className="-ml-0">
                {post.image_urls?.map((url, index) => {
                  const dims = imageDimensions[url];
                  const isLong = dims ? dims.height / dims.width > 1.5 : false;
                  return (
                    <CarouselItem key={index} className="pl-0 flex items-center justify-center">
                      {isLong ? (
                        <div 
                          className="w-full h-screen overflow-x-hidden overflow-y-scroll overscroll-contain"
                          onMouseDown={(e) => {
                            const target = e.currentTarget;
                            setLongImageScrollStart({ y: e.clientY, scrollTop: target.scrollTop });
                          }}
                          onMouseUp={(e) => {
                            if (longImageScrollStart) {
                              const deltaY = Math.abs(e.clientY - longImageScrollStart.y);
                              const deltaScroll = Math.abs(e.currentTarget.scrollTop - longImageScrollStart.scrollTop);
                              if (deltaY < 10 && deltaScroll < 10) {
                                setPreviewOpen(false);
                              }
                              setLongImageScrollStart(null);
                            }
                          }}
                          onTouchStart={(e) => {
                            const target = e.currentTarget;
                            setLongImageScrollStart({ y: e.touches[0].clientY, scrollTop: target.scrollTop });
                          }}
                          onTouchEnd={(e) => {
                            if (longImageScrollStart) {
                              const touch = e.changedTouches[0];
                              const deltaY = Math.abs(touch.clientY - longImageScrollStart.y);
                              const deltaScroll = Math.abs(e.currentTarget.scrollTop - longImageScrollStart.scrollTop);
                              // Use a slightly larger threshold for touch to account for touch inaccuracy
                              if (deltaY < 15 && deltaScroll < 15) {
                                e.preventDefault();
                                setPreviewOpen(false);
                              }
                              setLongImageScrollStart(null);
                            }
                          }}
                        >
                        <img
                              src={url}
                              alt=""
                              className="block select-none"
                              style={{
                                width: '100vw',
                                minHeight: '100dvh',
                                height: 'auto',
                                margin: 0
                              }}
                              draggable={false}
                              onLoad={(e) => handleImageLoad(e, url)}
                            />
                        </div>
                      ) : (
                        <div className="w-full h-full flex items-center justify-center">
                          <img
                            src={url}
                            alt=""
                            className="object-contain w-screen h-screen select-none cursor-pointer"
                            draggable={false}
                            onClick={() => setPreviewOpen(false)}
                            onLoad={(e) => handleImageLoad(e, url)}
                          />
                        </div>
                      )}
                    </CarouselItem>
                  );
                })}
              </CarouselContent>
            </Carousel>
          </div>

          {/* Desktop Navigation Buttons - connected to Carousel API */}
          {post.image_urls && post.image_urls.length > 1 && (
            <>
              <Button
                variant="ghost"
                size="icon"
                className="absolute left-4 top-1/2 -translate-y-1/2 z-10 text-white hover:bg-white/20 h-12 w-12 hidden sm:flex"
                onClick={() => previewCarouselApi?.scrollPrev()}
              >
                <ChevronLeft className="h-8 w-8" />
              </Button>
              <Button
                variant="ghost"
                size="icon"
                className="absolute right-4 top-1/2 -translate-y-1/2 z-10 text-white hover:bg-white/20 h-12 w-12 hidden sm:flex"
                onClick={() => previewCarouselApi?.scrollNext()}
              >
                <ChevronRight className="h-8 w-8" />
              </Button>
            </>
          )}
        </div>,
        document.body
      )}
      
      {/* Smart Share Drawer for WebView environments */}
      {SmartShareDrawer}

      {/* AI Recipe Source Dialog */}
      {(post as any).ai_recipe_source?.recipe_name && (
        <SavedRecipeDetailDialog
          open={showAiRecipeDialog}
          onOpenChange={setShowAiRecipeDialog}
          recipe={(post as any).ai_recipe_source as any}
          recipeName={
            getLocalizedField((post as any).ai_recipe_source, "recipe_name") || 
            (post as any).ai_recipe_source?.recipe_name || 
            ""
          }
          initialImageUrl={(post as any).ai_recipe_source?.image_url}
        />
      )}
    </>
  );
};

export default PostCard;
