import { useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { formatDistanceToNow } from "date-fns";
import { zhCN, enUS, pt } from "date-fns/locale";
import { Clock, Users, Utensils, Flame, ChefHat, PlayCircle, ChevronDown, ChevronUp, Quote } from "lucide-react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { CommunityPost } from "@/hooks/useCommunityPosts";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { RecipeStep, Ingredient, NutritionInfo } from "./RecipeTypes";
import TranslateButton from "@/components/TranslateButton";
import TranslatableText from "@/components/TranslatableText";
import ImagePreviewModal from "@/components/ImagePreviewModal";
import RecipeAds from "./RecipeAds";

// Parse structured content: [[NOTE]]心得\n[[INTRO]]介绍
const parseRecipeContent = (raw: string) => {
  const noteMatch = raw.match(/^\[\[NOTE\]\]([\s\S]*?)(?:\n\[\[INTRO\]\]|$)/);
  const introMatch = raw.match(/\[\[INTRO\]\]([\s\S]*)$/);
  if (noteMatch) {
    return {
      note: noteMatch[1].trim(),
      intro: introMatch ? introMatch[1].trim() : "",
    };
  }
  return { note: "", intro: raw };
};

interface ExtendedPost extends CommunityPost {
  post_type?: string;
  recipe_name?: string;
  recipe_name_en?: string;
  recipe_name_pt?: string;
  cook_time?: number;
  difficulty?: string;
  servings?: number;
  ingredients?: Ingredient[];
  steps?: RecipeStep[];
  nutrition?: NutritionInfo;
  recipe_tags?: string[];
  recipe_category?: string;
}

interface RecipeOverviewProps {
  post: ExtendedPost;
  onStartCooking: () => void;
}

const RecipeOverview = ({ post, onStartCooking }: RecipeOverviewProps) => {
  const { t, i18n } = useTranslation();
  const { getLocalizedField } = useLocalizedContent();
  const [translatedName, setTranslatedName] = useState<string | null>(null);
  const [translatedContent, setTranslatedContent] = useState<string | null>(null);
  const [translatedIngredients, setTranslatedIngredients] = useState<Record<number, string>>({});
  const [previewImageUrl, setPreviewImageUrl] = useState<string | null>(null);
  const [showFullContent, setShowFullContent] = useState(false);
  const [showAllIngredients, setShowAllIngredients] = useState(false);

  const CONTENT_MAX_LENGTH = 200;
  const INGREDIENTS_PREVIEW_COUNT = 5;

  // Get localized content - prioritize pre-stored translations
  const getLocalizedContent = () => {
    const langMap: Record<string, string> = {
      'zh': 'content_zh',
      'en': 'content_en', 
      'pt': 'content_pt'
    };
    const field = langMap[i18n.language] || 'content';
    const localizedValue = post[field as keyof typeof post];
    if (localizedValue && typeof localizedValue === 'string' && localizedValue.trim()) {
      return localizedValue;
    }
    return post.content;
  };

  const displayContent = translatedContent || getLocalizedContent();
  const parsedContent = useMemo(() => parseRecipeContent(displayContent || ""), [displayContent]);
  const displayName = translatedName || getLocalizedField(post, "recipe_name") || post.recipe_name;

  // Build combined text for translation: name + content + ingredients
  const buildTranslationText = () => {
    const parts: string[] = [];
    // Recipe name
    if (post.recipe_name) {
      parts.push(`[NAME]${post.recipe_name}`);
    }
    // Content (if exists and not auto-generated)
    if (post.content && post.content.trim() && !post.content.includes('主要配料：')) {
      parts.push(`[CONTENT]${post.content}`);
    }
    // Ingredients
    if (post.ingredients && post.ingredients.length > 0) {
      const ingredientNames = post.ingredients.map(i => i.name).join('|');
      parts.push(`[INGREDIENTS]${ingredientNames}`);
    }
    return parts.join('\n---\n');
  };

  // Parse translation result
  const handleTranslation = (translated: string | null) => {
    if (!translated) {
      setTranslatedName(null);
      setTranslatedContent(null);
      setTranslatedIngredients({});
      return;
    }
    
    const sections = translated.split('\n---\n');
    sections.forEach(section => {
      if (section.startsWith('[NAME]')) {
        setTranslatedName(section.replace('[NAME]', ''));
      } else if (section.startsWith('[CONTENT]')) {
        setTranslatedContent(section.replace('[CONTENT]', ''));
      } else if (section.startsWith('[INGREDIENTS]')) {
        const names = section.replace('[INGREDIENTS]', '').split('|');
        const map: Record<number, string> = {};
        names.forEach((name, idx) => { map[idx] = name.trim(); });
        setTranslatedIngredients(map);
      }
    });
  };

  const getDateLocale = () => {
    switch (i18n.language) {
      case "zh": return zhCN;
      case "pt": return pt;
      default: return enUS;
    }
  };

  const getDifficultyColor = (d: string) => {
    switch (d) {
      case 'easy': return 'bg-green-500/20 text-green-700 dark:text-green-400 border-green-500/30';
      case 'medium': return 'bg-yellow-500/20 text-yellow-700 dark:text-yellow-400 border-yellow-500/30';
      case 'hard': return 'bg-red-500/20 text-red-700 dark:text-red-400 border-red-500/30';
      default: return 'bg-muted text-muted-foreground';
    }
  };

  const getDifficultyLabel = (d: string) => {
    switch (d) {
      case 'easy': return t("recipe.difficulty.easy", "简单");
      case 'medium': return t("recipe.difficulty.medium", "中等");
      case 'hard': return t("recipe.difficulty.hard", "困难");
      default: return d;
    }
  };

  const hasImages = post.image_urls && post.image_urls.length > 0;
  const hasSteps = post.steps && post.steps.length > 0;

  return (
    <Card className="overflow-hidden">
      {/* Hero Image */}
      {hasImages && (
        <div className="relative aspect-video overflow-hidden">
          <img
            src={post.image_urls![0]}
            alt={displayName || ""}
            className="w-full h-full object-cover cursor-pointer"
            onClick={() => setPreviewImageUrl(post.image_urls![0])}
          />
          <Badge className="absolute top-3 left-3 bg-primary text-primary-foreground gap-1">
            <Utensils className="h-3 w-3" />
            {t("recipe.badge", "食谱")}
          </Badge>
        </div>
      )}

      <CardHeader className="pb-3">
        {/* Author */}
        <div className="flex items-center gap-3 mb-4">
          <Avatar className="h-10 w-10">
            <AvatarImage src={post.author?.avatar_url || undefined} />
            <AvatarFallback>
              {post.author?.display_name?.charAt(0) || "?"}
            </AvatarFallback>
          </Avatar>
          <div>
            <p className="font-medium text-sm">{post.author?.display_name}</p>
            <p className="text-xs text-muted-foreground">
              {formatDistanceToNow(new Date(post.created_at), {
                addSuffix: true,
                locale: getDateLocale(),
              })}
            </p>
          </div>
        </div>

        {/* Translate All Button - above recipe name */}
        <div className="mb-2">
          <TranslateButton 
            text={buildTranslationText()} 
            onTranslation={handleTranslation}
            label={t("recipe.translateAll")}
          />
        </div>

        {/* Recipe Name */}
        <h2 className="text-xl font-bold">{displayName}</h2>

        {/* Meta Info */}
        <div className="flex flex-wrap items-center gap-3 mt-3">
          {post.cook_time && (
            <div className="flex items-center gap-1.5 text-sm text-muted-foreground">
              <Clock className="h-4 w-4" />
              <span>{post.cook_time} {t("recipe.minutes", "分钟")}</span>
            </div>
          )}
          {post.servings && (
            <div className="flex items-center gap-1.5 text-sm text-muted-foreground">
              <Users className="h-4 w-4" />
              <span>{post.servings} {t("recipe.servings", "人份")}</span>
            </div>
          )}
          {post.difficulty && (
            <Badge variant="outline" className={getDifficultyColor(post.difficulty)}>
              <ChefHat className="h-3 w-3 mr-1" />
              {getDifficultyLabel(post.difficulty)}
            </Badge>
          )}
        </div>
      </CardHeader>

      <CardContent className="space-y-6">
        {/* Cooking Note + Description */}
        {post.content && post.content.trim() && !post.content.includes('主要配料：') && (
          <div className="space-y-3">
            {/* Cooking note - styled card */}
            {parsedContent.note && (
              <div className="rounded-lg border border-primary/20 bg-primary/5 px-4 py-3">
                <div className="flex items-center gap-1.5 mb-1.5">
                  <Quote className="h-3.5 w-3.5 text-primary" />
                  <span className="text-xs font-medium text-primary">{t("recipe.cookingNote", "心得")}</span>
                </div>
                <p className="text-sm text-foreground/80 italic leading-relaxed whitespace-pre-line">
                  {parsedContent.note}
                </p>
              </div>
            )}
            {/* Original AI introduction */}
            {parsedContent.intro && (
              <div>
                <p className="text-sm text-muted-foreground whitespace-pre-line leading-relaxed">
                  {showFullContent || parsedContent.intro.length <= CONTENT_MAX_LENGTH
                    ? parsedContent.intro
                    : parsedContent.intro.slice(0, CONTENT_MAX_LENGTH) + '...'}
                </p>
                {parsedContent.intro.length > CONTENT_MAX_LENGTH && (
                  <Button
                    variant="ghost"
                    size="sm"
                    className="px-0 h-auto py-1 text-xs text-primary"
                    onClick={() => setShowFullContent(!showFullContent)}
                  >
                    {showFullContent ? t("common.collapse", "收起") : t("common.viewAll", "查看全部")}
                    {showFullContent ? <ChevronUp className="h-3 w-3 ml-1" /> : <ChevronDown className="h-3 w-3 ml-1" />}
                  </Button>
                )}
              </div>
            )}
            {/* Legacy content without structured tags */}
            {!parsedContent.note && !parsedContent.intro && (
              <div>
                <p className="text-sm text-muted-foreground whitespace-pre-line">
                  {showFullContent || (displayContent || '').length <= CONTENT_MAX_LENGTH
                    ? displayContent
                    : (displayContent || '').slice(0, CONTENT_MAX_LENGTH) + '...'}
                </p>
                {(displayContent || '').length > CONTENT_MAX_LENGTH && (
                  <Button
                    variant="ghost"
                    size="sm"
                    className="px-0 h-auto py-1 text-xs text-primary"
                    onClick={() => setShowFullContent(!showFullContent)}
                  >
                    {showFullContent ? t("common.collapse", "收起") : t("common.viewAll", "查看全部")}
                    {showFullContent ? <ChevronUp className="h-3 w-3 ml-1" /> : <ChevronDown className="h-3 w-3 ml-1" />}
                  </Button>
                )}
              </div>
            )}
          </div>
        )}

        {/* Nutrition Info */}
        {post.nutrition && (post.nutrition.calories || post.nutrition.protein || post.nutrition.carbs || post.nutrition.fat) && (
          <div>
            <h3 className="font-semibold text-sm mb-3 flex items-center gap-2">
              <Flame className="h-4 w-4 text-orange-500" />
              {t("recipe.nutrition", "营养信息")}
            </h3>
            <div className="grid grid-cols-4 gap-2">
              {post.nutrition.calories && (
                <div className="text-center p-2 bg-muted/50 rounded-lg">
                  <p className="text-lg font-bold text-primary">{post.nutrition.calories}</p>
                  <p className="text-xs text-muted-foreground">{t("recipe.kcal", "千卡")}</p>
                </div>
              )}
              {post.nutrition.protein && (
                <div className="text-center p-2 bg-muted/50 rounded-lg">
                  <p className="text-lg font-bold text-primary">{post.nutrition.protein}g</p>
                  <p className="text-xs text-muted-foreground">{t("recipe.protein", "蛋白质")}</p>
                </div>
              )}
              {post.nutrition.carbs && (
                <div className="text-center p-2 bg-muted/50 rounded-lg">
                  <p className="text-lg font-bold text-primary">{post.nutrition.carbs}g</p>
                  <p className="text-xs text-muted-foreground">{t("recipe.carbs", "碳水")}</p>
                </div>
              )}
              {post.nutrition.fat && (
                <div className="text-center p-2 bg-muted/50 rounded-lg">
                  <p className="text-lg font-bold text-primary">{post.nutrition.fat}g</p>
                  <p className="text-xs text-muted-foreground">{t("recipe.fat", "脂肪")}</p>
                </div>
              )}
            </div>
          </div>
        )}

        <Separator />

        {/* Ingredients - collapsible */}
        {post.ingredients && post.ingredients.length > 0 && (
          <div>
            <h3 className="font-semibold text-sm mb-3">
              {t("recipe.ingredients", "食材")} ({post.ingredients.length})
            </h3>
            {/* Table header */}
            <div className="flex items-center text-xs text-muted-foreground font-medium px-2 py-1.5 bg-muted/50 rounded-t-md border border-border/50">
              <span className="flex-1">{t("recipe.ingredientName", "名称")}</span>
              <span className="w-24 text-right">{t("recipe.amount", "用量")}</span>
            </div>
            <ul className="border border-t-0 border-border/50 rounded-b-md divide-y divide-border/50">
              {(showAllIngredients ? post.ingredients : post.ingredients.slice(0, INGREDIENTS_PREVIEW_COUNT)).map((ingredient, index) => {
                const localName = translatedIngredients[index]
                  || (i18n.language === "en" && ingredient.name_en ? ingredient.name_en
                    : i18n.language === "pt" && ingredient.name_pt ? ingredient.name_pt
                    : ingredient.name);
                return (
                  <li key={index} className="flex items-center text-sm px-2 py-2">
                    <span className="flex-1 min-w-0 truncate">{localName}</span>
                    <span className="w-24 text-right text-muted-foreground shrink-0">
                      {ingredient.amount} {i18n.language === "en" && ingredient.unit_en ? ingredient.unit_en
                        : i18n.language === "pt" && ingredient.unit_pt ? ingredient.unit_pt
                        : ingredient.unit}
                    </span>
                  </li>
                );
              })}
            </ul>
            {post.ingredients.length > INGREDIENTS_PREVIEW_COUNT && (
              <>
                {showAllIngredients && <RecipeAds />}
                <Button
                  variant="ghost"
                  size="sm"
                  className="w-full mt-2 text-xs text-primary"
                  onClick={() => setShowAllIngredients(!showAllIngredients)}
                >
                  {showAllIngredients
                    ? t("common.collapse", "收起")
                    : t("recipe.showAllIngredients", { count: post.ingredients.length })}
                  {showAllIngredients ? <ChevronUp className="h-3 w-3 ml-1" /> : <ChevronDown className="h-3 w-3 ml-1" />}
                </Button>
              </>
            )}
            {/* Show ads when no collapse needed (fewer ingredients) */}
            {post.ingredients.length <= INGREDIENTS_PREVIEW_COUNT && <RecipeAds />}
          </div>
        )}

        {/* Tags */}
        {post.recipe_tags && post.recipe_tags.length > 0 && (
          <div className="flex flex-wrap gap-2 pt-2">
            {post.recipe_tags.map((tag, index) => (
              <Badge key={index} variant="secondary" className="text-xs">
                #{tag}
              </Badge>
            ))}
          </div>
        )}

        {/* Start Cooking Button */}
        {hasSteps && (
          <Button 
            size="lg" 
            className="w-full gap-2 h-14 text-lg"
            onClick={onStartCooking}
          >
            <PlayCircle className="h-6 w-6" />
            {t("recipe.startCooking", "开始烹饪")}
            <Badge variant="secondary" className="ml-2">
              {post.steps!.length} {t("recipe.stepsCount", "步")}
            </Badge>
          </Button>
        )}
      </CardContent>

      <ImagePreviewModal
        imageUrl={previewImageUrl || ""}
        isOpen={!!previewImageUrl}
        onClose={() => setPreviewImageUrl(null)}
      />
    </Card>
  );
};

export default RecipeOverview;
