interface WatermarkedVideoPlayerProps {
  videoUrl: string;
  poster?: string;
  className?: string;
}

/**
 * Simple video player. Watermark is baked into the video file itself,
 * so no overlay or fullscreen interception is needed.
 */
export default function WatermarkedVideoPlayer({ videoUrl, poster, className = "w-full max-h-96" }: WatermarkedVideoPlayerProps) {
  return (
    <video
      src={videoUrl}
      poster={poster}
      controls
      className={className}
      preload="metadata"
      playsInline
    />
  );
}
